"use client";

import { Dialog as SheetPrimitive } from "@base-ui/react/dialog";
import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { XIcon } from "@phosphor-icons/react";
import * as stylex from "@stylexjs/stylex";
import type React from "react";
import type { _BaseDivProps, PropsWithStylex } from "@/utils/stylex.utils";
import { Button } from "../Button/button";
import { ScrollArea } from "../ScrollArea/scroll-area";
import { sheetStyles } from "./sheet.styles";

type Side = "right" | "left" | "top" | "bottom";

export const Sheet: typeof SheetPrimitive.Root = SheetPrimitive.Root;

export const SheetPortal: typeof SheetPrimitive.Portal = SheetPrimitive.Portal;

export function SheetTrigger(
	props: SheetPrimitive.Trigger.Props,
): React.ReactElement {
	return <SheetPrimitive.Trigger data-slot="sheet-trigger" {...props} />;
}

export function SheetClose(
	props: SheetPrimitive.Close.Props,
): React.ReactElement {
	return <SheetPrimitive.Close data-slot="sheet-close" {...props} />;
}

export function SheetBackdrop({
	style,
	...props
}: PropsWithStylex<SheetPrimitive.Backdrop.Props>): React.ReactElement {
	return (
		<SheetPrimitive.Backdrop
			{...stylex.props(sheetStyles.backdrop, style)}
			data-slot="sheet-backdrop"
			{...props}
		/>
	);
}

type SheetViewportProps = PropsWithStylex<
	SheetPrimitive.Viewport.Props & {
		side?: Side;
		variant?: "default" | "inset";
	}
>;

export function SheetViewport({
	style,
	side,
	variant = "default",
	...props
}: SheetViewportProps): React.ReactElement {
	return (
		<SheetPrimitive.Viewport
			{...stylex.props(
				sheetStyles.viewport,
				side === "bottom" && sheetStyles.viewportBottom,
				side === "top" && sheetStyles.viewportTop,
				side === "left" && sheetStyles.viewportLeft,
				side === "right" && sheetStyles.viewportRight,
				variant === "inset" && sheetStyles.viewportInset,
				style,
			)}
			data-slot="sheet-viewport"
			{...props}
		/>
	);
}

export function SheetPopup({
	style,
	children,
	showCloseButton = true,
	side = "right",
	variant = "default",
	closeProps,
	portalProps,
	...props
}: PropsWithStylex<
	SheetPrimitive.Popup.Props & {
		showCloseButton?: boolean;
		side?: Side;
		variant?: "default" | "inset";
		closeProps?: SheetPrimitive.Close.Props;
		portalProps?: SheetPrimitive.Portal.Props;
	}
>): React.ReactElement {
	return (
		<SheetPortal {...portalProps}>
			<SheetBackdrop />
			<SheetViewport side={side} variant={variant}>
				<SheetPrimitive.Popup
					{...stylex.props(
						sheetStyles.popup,
						side === "bottom" && sheetStyles.popupBottom,
						side === "top" && sheetStyles.popupTop,
						side === "left" && sheetStyles.popupLeft,
						side === "right" && sheetStyles.popupRight,
						variant === "inset" && sheetStyles.popupInset,
						style,
					)}
					data-slot="sheet-popup"
					{...props}
				>
					{children}
					{showCloseButton && (
						<SheetPrimitive.Close
							aria-label="Close"
							className={stylex.props(sheetStyles.closeButton).className}
							render={<Button size="icon" variant="ghost" />}
							{...closeProps}
						>
							<XIcon />
						</SheetPrimitive.Close>
					)}
				</SheetPrimitive.Popup>
			</SheetViewport>
		</SheetPortal>
	);
}

type HeaderProps = useRender.ComponentProps<"div">;

export function SheetHeader({
	render,
	...props
}: HeaderProps): React.ReactElement {
	const headerProps = stylex.props(sheetStyles.header);
	return useRender({
		defaultTagName: "div",
		props: mergeProps<"div">(
			{
				...headerProps,
				"data-slot": "sheet-header",
			} as never,
			props,
		),
		render,
	});
}

type FooterProps = _BaseDivProps & {
	variant?: "default" | "bare";
};

export function SheetFooter({
	style,
	variant = "default",
	render,
	...props
}: FooterProps): React.ReactElement {
	const footerProps = stylex.props(
		sheetStyles.footer,
		variant === "default" && sheetStyles.footerDefault,
		variant === "bare" && sheetStyles.footerBare,
		style,
	);
	return useRender({
		defaultTagName: "div",
		props: mergeProps<"div">(
			{
				...footerProps,
				"data-slot": "sheet-footer",
			} as never,
			props,
		),
		render,
	});
}

export function SheetTitle(
	props: SheetPrimitive.Title.Props,
): React.ReactElement {
	return (
		<SheetPrimitive.Title
			{...stylex.props(sheetStyles.title)}
			data-slot="sheet-title"
			{...props}
		/>
	);
}

export function SheetDescription(
	props: SheetPrimitive.Description.Props,
): React.ReactElement {
	return (
		<SheetPrimitive.Description
			{...stylex.props(sheetStyles.description)}
			data-slot="sheet-description"
			{...props}
		/>
	);
}

type PanelProps = _BaseDivProps & {
	scrollFade?: boolean;
};

export function SheetPanel({
	style,
	scrollFade = true,
	render,
	...props
}: PanelProps): React.ReactElement {
	const panelProps = stylex.props(sheetStyles.panel, style);
	return (
		<ScrollArea scrollFade={scrollFade}>
			{useRender({
				defaultTagName: "div",
				props: mergeProps<"div">(
					{
						...panelProps,
						"data-slot": "sheet-panel",
					} as never,
					props,
				),
				render,
			})}
		</ScrollArea>
	);
}

export type { SheetViewportProps };

export { SheetBackdrop as SheetOverlay, SheetPopup as SheetContent };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	borderWidth,
	fontSize,
	fontWeight,
	mediaQueries,
	spacing,
} from "@/lib/theme/tokens.stylex";

export const sheetStyles = stylex.create({
	backdrop: {
		position: "fixed",
		inset: 0,
		zIndex: 50,
		backgroundColor: "rgba(0, 0, 0, 0.32)",
		backdropFilter: "blur(4px)",
		transitionProperty: {
			default: "opacity",
			"@media (prefers-reduced-motion: reduce)": "none",
		},
		transitionDuration: {
			default: "200ms",
			"@media (prefers-reduced-motion: reduce)": "0ms",
		},
		"[data-starting-style]": {
			opacity: 0,
		},
		"[data-ending-style]": {
			opacity: 0,
		},
	},
	viewport: {
		position: "fixed",
		inset: 0,
		zIndex: 50,
		boxSizing: "border-box",
	},
	viewportBottom: {
		display: "grid",
		gridTemplateRows: "1fr auto",
		paddingTop: spacing.xxlarge,
	},
	viewportTop: {
		display: "grid",
		gridTemplateRows: "auto 1fr",
		paddingBottom: spacing.xxlarge,
	},
	viewportLeft: {
		display: "flex",
		justifyContent: "flex-start",
	},
	viewportRight: {
		display: "flex",
		justifyContent: "flex-end",
	},
	viewportInset: {
		padding: {
			default: null,
			[mediaQueries.sm]: spacing.medium,
		},
	},
	popup: {
		position: "relative",
		display: "flex",
		flexDirection: "column",
		maxHeight: "100%",
		minHeight: 0,
		minWidth: 0,
		width: "100%",
		boxSizing: "border-box",
		backgroundColor: theme.surface,
		color: theme.contentPrimary,
		borderStyle: "solid",
		borderColor: theme.border,
		outline: "none",
		boxShadow: theme.shadowLg,
		willChange: "translate",
		transitionProperty: {
			default: "opacity, translate",
			"@media (prefers-reduced-motion: reduce)": "none",
		},
		transitionDuration: {
			default: "200ms",
			"@media (prefers-reduced-motion: reduce)": "0ms",
		},
		transitionTimingFunction: "ease-in-out",
		"::before": {
			content: '""',
			pointerEvents: "none",
			position: "absolute",
			inset: 0,
			boxShadow:
				"0 1px 0 rgba(0, 0, 0, 0.04), inset 0 0 0 1px rgba(255, 255, 255, 0.02)",
		},
	},
	popupBottom: {
		gridRowStart: 2,
		borderTopWidth: borderWidth.thin,
		borderTopLeftRadius: borderRadius.xlarge,
		borderTopRightRadius: borderRadius.xlarge,
		"[data-starting-style]": {
			opacity: 0,
			translate: "0 32px",
		},
		"[data-ending-style]": {
			opacity: 0,
			translate: "0 32px",
		},
	},
	popupTop: {
		borderBottomWidth: borderWidth.thin,
		borderBottomLeftRadius: borderRadius.xlarge,
		borderBottomRightRadius: borderRadius.xlarge,
		"[data-starting-style]": {
			opacity: 0,
			translate: "0 -32px",
		},
		"[data-ending-style]": {
			opacity: 0,
			translate: "0 -32px",
		},
	},
	popupLeft: {
		width: "calc(100% - 48px)",
		maxWidth: "28rem",
		borderRightWidth: borderWidth.thin,
		borderTopRightRadius: borderRadius.xlarge,
		borderBottomRightRadius: borderRadius.xlarge,
		"[data-starting-style]": {
			opacity: 0,
			translate: "-32px 0",
		},
		"[data-ending-style]": {
			opacity: 0,
			translate: "-32px 0",
		},
	},
	popupRight: {
		width: "calc(100% - 48px)",
		maxWidth: "28rem",
		borderLeftWidth: borderWidth.thin,
		borderTopLeftRadius: borderRadius.xlarge,
		borderBottomLeftRadius: borderRadius.xlarge,
		"[data-starting-style]": {
			opacity: 0,
			translate: "32px 0",
		},
		"[data-ending-style]": {
			opacity: 0,
			translate: "32px 0",
		},
	},
	popupInset: {
		"::before": null,
		borderRadius: {
			default: 0,
			[mediaQueries.sm]: borderRadius.xlarge,
		},
		borderWidth: {
			default: 0,
			[mediaQueries.sm]: borderWidth.thin,
		},
	},
	closeButton: {
		position: "absolute",
		top: spacing.xsmall,
		insetInlineEnd: spacing.xsmall,
	},
	header: {
		display: "flex",
		flexDirection: "column",
		gap: spacing.small,
		padding: spacing.large,
		boxSizing: "border-box",
	},
	footer: {
		display: "flex",
		flexDirection: {
			default: "column-reverse",
			[mediaQueries.sm]: "row",
		},
		gap: spacing.small,
		paddingLeft: spacing.large,
		paddingRight: spacing.large,
		boxSizing: "border-box",
		justifyContent: {
			[mediaQueries.sm]: "flex-end",
		},
	},
	footerDefault: {
		borderTopWidth: borderWidth.thin,
		borderTopStyle: "solid",
		borderTopColor: theme.borderSubtle,
		backgroundColor: theme.backgroundSubtle,
		paddingTop: spacing.medium,
		paddingBottom: spacing.medium,
	},
	footerBare: {
		paddingTop: spacing.medium,
		paddingBottom: spacing.large,
	},
	title: {
		fontSize: fontSize.xlarge,
		lineHeight: 1,
		fontWeight: fontWeight.semibold,
	},
	description: {
		fontSize: fontSize.small,
		lineHeight: 1.4,
		color: theme.contentSecondary,
	},
	panel: {
		boxSizing: "border-box",
		padding: spacing.large,
	},
});
